#!/usr/bin/env bash
# mass-equip.sh — provision EVERY connected R1 into the mesh in one shot.
# The "mass" wrapper around equip.sh for the catch-and-release fleet phase: plug in
# N R1s, run this once, and they self-assign stages (with replicas as N grows) and
# form a self-organizing, brick-tolerant WiFi mesh.
#
# Stage assignment: the model's layer range is split into STAGES (default the proven
# qwen 2-stage 0..12,12..24). Devices are dealt round-robin across stages, so:
#   1 device  -> 1 stage covered (incomplete)         2 -> both stages, 1 replica each
#   3 devices -> stage0 x2, stage1 x1 (redundancy!)   4 -> 2 replicas/stage, etc.
# The first device is the gossip seed; every node peers to it (and it to the 2nd),
# so membership converges. role = entry (stage starts at 0) | exit (stage ends at
# the model's last layer) | mid (otherwise).
#
# Usage:
#   mass-equip.sh [--stages "0..12,12..24"] [--knot /data/local/tmp/qwen05-dense.knot]
#                 [--gossip-port 9090] [--data-port 8090] [--tcpip]
set -euo pipefail
HERE="$(cd "$(dirname "$0")" && pwd)"
STAGES="0..12,12..24"; KNOT="/data/local/tmp/qwen05-dense.knot"
GPORT=9090; DPORT=8090; TCPIP=""; ADMIT=""; TREP=2; APKARG=""
# Component 3: host-side RAM-aware stage elector (built from src/bin/mesh-elect.rs).
MELECT="$HERE/../../target/release/mesh-elect"
while [ $# -gt 0 ]; do case "$1" in
  --stages) STAGES=$2; shift 2;; --knot) KNOT=$2; shift 2;;
  --gossip-port) GPORT=$2; shift 2;; --data-port) DPORT=$2; shift 2;;
  --target-replicas) TREP=$2; shift 2;;
  --apk) APKARG="--apk $2"; shift 2;;
  --tcpip) TCPIP="--tcpip"; shift;; --admit) ADMIT="--admit"; shift;;
  *) echo "unknown arg: $1" >&2; exit 2;; esac; done

IFS=',' read -r -a STAGE_ARR <<< "$STAGES"
NSTAGES=${#STAGE_ARR[@]}
MAX_LAYER=0
for s in "${STAGE_ARR[@]}"; do e=${s##*..}; [ "$e" -gt "$MAX_LAYER" ] && MAX_LAYER=$e; done

SERIALS=()
while IFS= read -r line; do [ -n "$line" ] && SERIALS+=("$line"); done < <(adb devices | awk '/\tdevice$/{print $1}')
N=${#SERIALS[@]}
[ "$N" -gt 0 ] || { echo "no adb devices connected" >&2; exit 1; }
echo "[mass-equip] $N device(s), $NSTAGES stage(s) [$STAGES], model=$KNOT"

# Seed = first device's wifi gossip endpoint (others bootstrap from it).
SEED_IP=$(adb -s "${SERIALS[0]}" shell 'ip -o -4 addr show wlan0 2>/dev/null | awk "{print \$4}" | cut -d/ -f1' | tr -d '\r')
[ -n "$SEED_IP" ] || { echo "[mass-equip] first device has no wifi IP — join WiFi first" >&2; exit 1; }
SEED="$SEED_IP:$GPORT"
echo "[mass-equip] gossip seed = $SEED"

i=0
for S in "${SERIALS[@]}"; do
  # Stage = RAM-aware election (component 3). The first device has no mesh to query and
  # seeds as the entry; every later device asks the live seed which stage best balances
  # the mesh given its own free RAM (fill under-replicated first; bigger nodes -> bigger
  # shards). A node's stage is fixed here, at SHARD-ASSIGNMENT time. Falls back to static
  # round-robin if the elector binary is missing or the seed can't be reached.
  STAGE=${STAGE_ARR[$((i % NSTAGES))]}
  if [ "$i" -gt 0 ] && [ -x "$MELECT" ]; then
    CAP=$(adb -s "$S" shell 'cat /proc/meminfo' | awk '/MemAvailable/{print int($2/1024)}' | tr -d '\r')
    ELECTED=$("$MELECT" --seed "http://$SEED_IP:$DPORT" --stages "$STAGES" \
                --capacity-mb "${CAP:-2048}" --target-replicas "$TREP" 2>/dev/null) || ELECTED=""
    if [ -n "$ELECTED" ]; then
      echo "[mass-equip] elect: $S free=${CAP:-?}MB -> stage $ELECTED (vs round-robin $STAGE)"
      STAGE="$ELECTED"
    else
      echo "[mass-equip] elect: $S elector returned nothing (mesh full / seed busy) -> round-robin $STAGE"
    fi
  fi
  A=${STAGE%%..*}; B=${STAGE##*..}
  if   [ "$A" = "0" ];           then ROLE=entry
  elif [ "$B" = "$MAX_LAYER" ];  then ROLE=exit
  else ROLE=mid; fi
  NODE="r1-$i"
  # First device seeds to the 2nd (if any) so the graph is bidirectional; others -> seed.
  if [ "$i" = "0" ] && [ "$N" -gt 1 ]; then
    PEERS=$(adb -s "${SERIALS[1]}" shell 'ip -o -4 addr show wlan0 2>/dev/null | awk "{print \$4}" | cut -d/ -f1' | tr -d '\r'):$GPORT
  elif [ "$i" = "0" ]; then PEERS=""
  else PEERS="$SEED"; fi
  echo "[mass-equip] -> $NODE  $S  stage=$STAGE role=$ROLE peers=${PEERS:-none}"
  bash "$HERE/equip.sh" -s "$S" -r "$ROLE" -l "$STAGE" -n "$NODE" -p "$PEERS" \
       -k "$KNOT" -P "$DPORT" -G "$GPORT" $TCPIP $ADMIT $APKARG 2>&1 | sed 's/^/    /' | grep -E "wakelock|OK:|WARN|admission|in-app|APK|launcher|done|error" || true
  i=$((i + 1))
done
echo "[mass-equip] fleet up. inspect any node: curl http://$SEED_IP:$DPORT/mesh/hive | (decode 2002 digest)"
echo "[mass-equip] drive inference: POST tokens to any entry node's /chain"
